 5→const Nebula = React.memo(({ x, y, radius, opacity, color }) => {
 6→    // 4 concentric circles at increasing opacity to simulate soft cloud glow
 7→    const layers = [
 8→        { rFactor: 1.0, opFactor: 0.3 },
